# conftest.py: E2E test environment setup
import pytest
from playwright.sync_api import Playwright

@pytest.fixture(scope="session")
def staging_url():
    return "https://staging.example.com"

@pytest.fixture(scope="session")
def browser_context(playwright: Playwright, staging_url):
    browser = playwright.chromium.launch(headless=True)
    context = browser.new_context(
        base_url=staging_url,
        record_video_dir="tests/e2e/videos/",
    )
    yield context
    context.close()
    browser.close()

@pytest.fixture(autouse=True)
def reset_staging_db():
    """Reset staging database before each E2E test."""
    import subprocess
    subprocess.run(["python3", "scripts/seed_staging_db.py", "--reset"], check=True)

@pytest.fixture
def page(browser_context, request):
    page = browser_context.new_page()
    yield page
    # Capture screenshot on failure
    if request.node.rep_call.failed:
        page.screenshot(path=f"tests/e2e/screenshots/{request.node.name}.png")
    page.close()
